import{bQ as s,aL as a,u as i,G as d}from"./chunks/framework.D06dwy5q.js";const E=JSON.parse('{"title":"前端和后端","description":"","frontmatter":{},"headers":[],"relativePath":"00.互联网与架构基础/05-前端和后端.md","filePath":"00.互联网与架构基础/05-前端和后端.md","lastUpdated":null}'),e={name:"00.互联网与架构基础/05-前端和后端.md"};function h(n,t,r,p,l,o){return a(),i("div",null,[...t[0]||(t[0]=[d(`<h1 id="前端和后端" tabindex="-1">前端和后端 <a class="header-anchor" href="#前端和后端" aria-label="Permalink to &quot;前端和后端&quot;">​</a></h1><p>打开一个网站时，屏幕上看到的页面属于前端。登录、保存、查询、统计这些动作，通常要交给后端处理。前端和后端之间用 HTTP 接口传数据，最常见的数据格式是 JSON。</p><p>把前端和后端分开看，排查问题会清楚很多。按钮点了没反应，可能是浏览器里的 JavaScript 报错；接口返回 500，通常要看后端日志；接口返回 200 但页面空白，可能是字段名和前端预期不一致。</p><h2 id="一、浏览器里的前端" tabindex="-1">一、浏览器里的前端 <a class="header-anchor" href="#一、浏览器里的前端" aria-label="Permalink to &quot;一、浏览器里的前端&quot;">​</a></h2><p>前端运行在浏览器里。浏览器读取 HTML 生成页面结构，读取 CSS 生成样式，执行 JavaScript 处理交互和接口请求。</p><table tabindex="0"><thead><tr><th>技术</th><th>作用</th></tr></thead><tbody><tr><td>HTML</td><td>页面上有哪些内容</td></tr><tr><td>CSS</td><td>页面长什么样</td></tr><tr><td>JavaScript</td><td>点击、输入、弹窗、接口请求</td></tr></tbody></table><p>一个按钮能正常工作，要同时满足几件事：按钮在 HTML 里存在，CSS 没把它遮住，JavaScript 绑定了点击事件，点击后发出的接口请求也正常返回。</p><p>前端源码通常会被打包成浏览器能加载的静态文件。发布时常见产物是 <code>index.html</code>、<code>assets/*.js</code>、<code>assets/*.css</code>、图片和字体。这些文件可以放在 Nginx、对象存储或 CDN 上。</p><h2 id="二、服务器里的后端" tabindex="-1">二、服务器里的后端 <a class="header-anchor" href="#二、服务器里的后端" aria-label="Permalink to &quot;二、服务器里的后端&quot;">​</a></h2><p>后端服务运行在服务器上，负责处理请求、访问数据库、调用其他服务、返回结果。Python 的 FastAPI、Go 的 HTTP 服务、Java 的 Spring Boot、Node.js 的 Express，都可以作为后端服务。</p><p>后端里常见对象：</p><table tabindex="0"><thead><tr><th>对象</th><th>含义</th></tr></thead><tbody><tr><td>路由</td><td>把请求路径交给对应函数处理</td></tr><tr><td>处理函数</td><td>读取参数、做业务处理、返回结果</td></tr><tr><td>模型</td><td>描述业务对象或数据库表</td></tr><tr><td>数据库连接</td><td>读写 MySQL、PostgreSQL、Redis 等</td></tr><tr><td>中间件</td><td>处理认证、日志、跨域、异常</td></tr></tbody></table><p>后端程序一般监听一个端口，例如 <code>8080</code>。公网用户通常不会直接访问这个端口，而是经过 Nginx、负载均衡或网关转发进来。</p><h2 id="三、json-接口" tabindex="-1">三、JSON 接口 <a class="header-anchor" href="#三、json-接口" aria-label="Permalink to &quot;三、JSON 接口&quot;">​</a></h2><p>前后端分离后，后端常返回 JSON。JSON 是一种文本格式，能表达对象、列表、字符串、数字和布尔值。</p><p>一个任务列表接口可能返回：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;items&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    {</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;巡检 web-01&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;status&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;success&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">},</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    {</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;备份 mysql-01&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;status&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;running&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;total&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>前端拿到这段数据后，把 <code>items</code> 渲染成表格或卡片。后端要保证字段名、类型和含义稳定，前端才能按固定方式展示。</p><p>字段不一致时，页面会出现很具体的问题。比如后端返回 <code>task_status</code>，前端代码读 <code>status</code>，Network 面板里接口状态码是 200，但页面状态列可能是空的。这种问题不在 Nginx，也不在数据库连接，而在接口字段没有对齐。</p><h2 id="四、分开部署" tabindex="-1">四、分开部署 <a class="header-anchor" href="#四、分开部署" aria-label="Permalink to &quot;四、分开部署&quot;">​</a></h2><p>前后端分离以后，静态页面和后端接口可以独立部署。</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20Browser%5B%22%E6%B5%8F%E8%A7%88%E5%99%A8%22%5D%0A%20%20CDN%5B%22CDN%20%2F%20Nginx%20%E9%9D%99%E6%80%81%E8%B5%84%E6%BA%90%22%5D%0A%20%20API%5B%22%E5%90%8E%E7%AB%AF%20API%22%5D%0A%20%20DB%5B%22%E6%95%B0%E6%8D%AE%E5%BA%93%22%5D%0A%0A%20%20Browser%20--%3E%20CDN%0A%20%20Browser%20--%3E%20API%0A%20%20API%20--%3E%20DB%0A"></div><p>浏览器第一次请求拿到 <code>index.html</code> 和 JS 文件；JS 运行后再请求 <code>/api/...</code>。同一个页面可能同时访问静态资源域名和接口域名。</p><p>常见位置：</p><table tabindex="0"><thead><tr><th>内容</th><th>常见位置</th></tr></thead><tbody><tr><td>前端静态文件</td><td>Nginx、对象存储、CDN</td></tr><tr><td>后端 API</td><td>虚拟机、容器、Kubernetes</td></tr><tr><td>数据库</td><td>云数据库、自建数据库、集群</td></tr><tr><td>入口层</td><td>Nginx、API 网关、Ingress</td></tr></tbody></table><h2 id="五、跨域" tabindex="-1">五、跨域 <a class="header-anchor" href="#五、跨域" aria-label="Permalink to &quot;五、跨域&quot;">​</a></h2><p>浏览器有同源策略。协议、域名、端口任意一个不同，就属于不同源。例如 <code>https://console.example.com</code> 调用 <code>https://api.example.com</code>，域名不同，浏览器会按跨域请求处理。</p><p>后端需要返回正确的 CORS Header，浏览器才允许前端代码读取响应。跨域失败时，后端可能已经正常返回数据，但浏览器拦住了 JavaScript 读取响应的动作。</p><p>跨域报错常见在浏览器控制台里。一个典型现象是 Network 面板里能看到预检请求 <code>OPTIONS</code>，但响应头里没有允许的 <code>Access-Control-Allow-Origin</code>，页面接口调用失败。</p><h2 id="六、联调时看哪里" tabindex="-1">六、联调时看哪里 <a class="header-anchor" href="#六、联调时看哪里" aria-label="Permalink to &quot;六、联调时看哪里&quot;">​</a></h2><p>前后端联调最容易混的是“接口通了”和“页面可用”。</p><table tabindex="0"><thead><tr><th>现象</th><th>更接近的位置</th></tr></thead><tbody><tr><td>接口返回 401</td><td>登录状态、Token、Cookie</td></tr><tr><td>接口返回 404</td><td>API 路径、网关转发、后端路由</td></tr><tr><td>接口返回 500</td><td>后端应用、数据库、下游服务</td></tr><tr><td>接口 200 但页面空</td><td>字段名、数据结构、前端渲染逻辑</td></tr><tr><td>控制台 CORS 报错</td><td>跨域配置</td></tr><tr><td>JS 文件 404</td><td>前端构建路径、静态资源发布路径</td></tr></tbody></table><p>前端和后端通过 HTTP 接口接在一起。页面问题要看浏览器里的请求和控制台，后端问题要看应用日志、接口状态码、数据库和下游调用。</p>`,33)])])}const c=s(e,[["render",h]]);export{E as __pageData,c as default};
